## 完整解决方案：支持 Reasoning + Tools

### 方案 1：创建自定义 Agent（推荐，最稳定）

创建文件 `reasoning_agent.py`：

```python
"""Custom agent that supports OpenAI Responses API with tools."""

import json
from typing import Any, Dict, List, Sequence, Optional
from langchain_core.tools import BaseTool
from langchain_core.messages import AIMessage, HumanMessage, ToolMessage
from openai import AsyncOpenAI


class ReasoningAgent:
    """Agent that supports OpenAI Responses API with reasoning and tools."""

    def __init__(
        self,
        model: str,
        tools: Sequence[BaseTool],
        reasoning: Optional[Dict[str, str]] = None,
        output_version: str = "responses/v1",
        max_iterations: int = 10,
        api_key: Optional[str] = None,
    ):
        self.model = model
        self.tools = {tool.name: tool for tool in tools}
        self.reasoning = reasoning or {"effort": "high", "summary": "detailed"}
        self.output_version = output_version
        self.max_iterations = max_iterations
        self.client = AsyncOpenAI(api_key=api_key)

        # 准备工具定义
        self.tool_definitions = self._prepare_tool_definitions(tools)

    def _prepare_tool_definitions(self, tools: Sequence[BaseTool]) -> List[Dict]:
        """Convert LangChain tools to OpenAI format."""
        definitions = []
        for tool in tools:
            definition = {
                "type": "function",
                "function": {
                    "name": tool.name,
                    "description": tool.description,
                }
            }

            # 添加参数 schema
            if hasattr(tool, 'args_schema') and tool.args_schema:
                try:
                    definition["function"]["parameters"] = tool.args_schema.schema()
                except Exception:
                    definition["function"]["parameters"] = {
                        "type": "object",
                        "properties": {}
                    }
            else:
                definition["function"]["parameters"] = {
                    "type": "object",
                    "properties": {}
                }

            definitions.append(definition)

        return definitions

    async def _execute_tool(self, tool_name: str, tool_args: Dict[str, Any]) -> str:
        """Execute a tool and return its result."""
        tool = self.tools.get(tool_name)
        if not tool:
            return f"Error: Tool '{tool_name}' not found"

        try:
            if hasattr(tool, 'ainvoke'):
                result = await tool.ainvoke(tool_args)
            else:
                result = tool.invoke(tool_args)
            return str(result)
        except Exception as e:
            return f"Error executing tool '{tool_name}': {str(e)}"

    def _convert_to_input_format(self, messages: List[Dict]) -> List[Dict]:
        """Convert messages to Responses API input format."""
        converted = []
        for msg in messages:
            role = msg.get("role")
            content = msg.get("content")

            if role in ["user", "system"]:
                converted.append({"role": role, "content": content})
            elif role == "assistant":
                assistant_msg = {"role": "assistant"}
                if content:
                    assistant_msg["content"] = content
                if "tool_calls" in msg:
                    assistant_msg["tool_calls"] = msg["tool_calls"]
                converted.append(assistant_msg)
            elif role == "tool":
                converted.append({
                    "role": "tool",
                    "tool_call_id": msg.get("tool_call_id"),
                    "content": content
                })

        return converted

    async def ainvoke(self, input_data: Dict[str, Any]) -> Dict[str, Any]:
        """
        Invoke the agent with reasoning and tool support.

        Args:
            input_data: Dict with "messages" key containing list of messages

        Returns:
            Dict with "messages" key containing full conversation history
        """
        messages = input_data.get("messages", [])

        # 转换初始消息格式
        conversation = []
        for msg in messages:
            if isinstance(msg, dict):
                conversation.append(msg)
            else:
                # 处理 BaseMessage 对象
                if hasattr(msg, 'type'):
                    conversation.append({
                        "role": msg.type,
                        "content": msg.content
                    })

        # Agent 循环
        for iteration in range(self.max_iterations):
            # 转换为 Responses API 格式
            input_messages = self._convert_to_input_format(conversation)

            # 调用 Responses API
            try:
                response = await self.client.responses.create(
                    model=self.model,
                    input=input_messages,
                    reasoning=self.reasoning,
                    tools=self.tool_definitions,
                    output_version=self.output_version,
                )
            except Exception as e:
                # 如果是第一次迭代就失败，直接返回错误
                if iteration == 0:
                    raise e
                # 否则返回当前结果
                break

            # 解析响应
            if not response.output or len(response.output) == 0:
                break

            last_output = response.output[-1]

            # 构建 assistant 消息
            assistant_msg = {"role": "assistant"}

            # 提取内容
            if hasattr(last_output, 'content'):
                if isinstance(last_output.content, list):
                    # 多部分内容
                    text_parts = []
                    for part in last_output.content:
                        if isinstance(part, dict) and part.get('type') == 'text':
                            text_parts.append(part.get('text', ''))
                        elif hasattr(part, 'text'):
                            text_parts.append(part.text)
                    assistant_msg["content"] = '\n'.join(text_parts)
                else:
                    assistant_msg["content"] = str(last_output.content)
            else:
                assistant_msg["content"] = ""

            # 检查工具调用
            has_tool_calls = False
            if hasattr(last_output, 'tool_calls') and last_output.tool_calls:
                has_tool_calls = True
                tool_calls_data = []

                for tc in last_output.tool_calls:
                    tool_call_dict = {
                        "id": tc.id,
                        "type": "function",
                        "function": {
                            "name": tc.function.name,
                            "arguments": tc.function.arguments
                        }
                    }
                    tool_calls_data.append(tool_call_dict)

                assistant_msg["tool_calls"] = tool_calls_data

            # 添加到对话历史
            conversation.append(assistant_msg)

            # 如果没有工具调用，结束循环
            if not has_tool_calls:
                break

            # 执行工具调用
            for tc in last_output.tool_calls:
                tool_name = tc.function.name

                # 解析参数
                try:
                    if isinstance(tc.function.arguments, str):
                        tool_args = json.loads(tc.function.arguments)
                    else:
                        tool_args = tc.function.arguments
                except json.JSONDecodeError:
                    tool_args = {}

                # 执行工具
                tool_result = await self._execute_tool(tool_name, tool_args)

                # 添加工具结果到对话
                conversation.append({
                    "role": "tool",
                    "tool_call_id": tc.id,
                    "content": tool_result
                })

        # 转换回 LangChain 消息格式
        lc_messages = []
        for msg in conversation:
            role = msg.get("role")
            content = msg.get("content", "")

            if role == "user":
                lc_messages.append(HumanMessage(content=content))
            elif role == "assistant":
                tool_calls = None
                if "tool_calls" in msg:
                    tool_calls = [
                        {
                            "id": tc["id"],
                            "name": tc["function"]["name"],
                            "args": json.loads(tc["function"]["arguments"]) 
                                    if isinstance(tc["function"]["arguments"], str)
                                    else tc["function"]["arguments"]
                        }
                        for tc in msg["tool_calls"]
                    ]
                lc_messages.append(AIMessage(content=content, tool_calls=tool_calls))
            elif role == "tool":
                lc_messages.append(ToolMessage(
                    content=content,
                    tool_call_id=msg.get("tool_call_id")
                ))

        return {"messages": lc_messages}


def create_reasoning_agent(
    model: str,
    tools: Sequence[BaseTool],
    reasoning: Optional[Dict[str, str]] = None,
    **kwargs
) -> ReasoningAgent:
    """
    Factory function to create a reasoning agent.

    Args:
        model: Model name (e.g., "gpt-4o")
        tools: List of tools
        reasoning: Reasoning config, e.g., {"effort": "high", "summary": "detailed"}
        **kwargs: Additional arguments

    Returns:
        ReasoningAgent instance
    """
    return ReasoningAgent(
        model=model,
        tools=tools,
        reasoning=reasoning,
        **kwargs
    )
```

### 使用方式

```python
import json
from reasoning_agent import create_reasoning_agent
from langchain_community.tools import DuckDuckGoSearchRun
from langchain_core.tools import tool

# 定义工具
search = DuckDuckGoSearchRun()

@tool
def get_weather(location: str) -> str:
    """Get the weather for a location."""
    # 这里是示例，实际应该调用天气 API
    return f"Weather in {location}: Sunny, 22°C"

tools = [search, get_weather]

# 创建 agent
reasoning = {
    "effort": "high",
    "summary": "detailed",
}

agent = create_reasoning_agent(
    model="gpt-4o",
    tools=tools,
    reasoning=reasoning,
    output_version="responses/v1",
    max_iterations=10,
)

# 使用 agent
with open("your_file.jsonl", "r") as f:
    for idx, line in enumerate(f):
        info = line.strip()
        if info:
            info = json.loads(info)

        question_info = info["messages"][1]
        assert question_info["role"] == "user"
        question = question_info["content"]

        result = await agent.ainvoke({
            "messages": [{"role": "user", "content": question}]
        })

        print("Question:", question)
        print("Answer:", result["messages"][-1].content)
        print("=" * 50)

        if idx >= 2:
            break
