### 方案 2：如果你的工具很简单，使用轻量级实现

```python
from openai import AsyncOpenAI
import json

async def simple_reasoning_agent(
    question: str,
    tools: list,
    model: str = "gpt-4o",
    reasoning: dict = None,
    max_iterations: int = 10
):
    """Simplified reasoning agent with tools."""

    client = AsyncOpenAI()
    reasoning = reasoning or {"effort": "high", "summary": "detailed"}

    # 工具定义
    tool_defs = [
        {
            "type": "function",
            "function": {
                "name": tool.name,
                "description": tool.description,
                "parameters": tool.args_schema.schema() if hasattr(tool, 'args_schema') else {}
            }
        }
        for tool in tools
    ]

    # 工具映射
    tool_map = {tool.name: tool for tool in tools}

    messages = [{"role": "user", "content": question}]

    for _ in range(max_iterations):
        # 调用 API
        response = await client.responses.create(
            model=model,
            input=messages,
            reasoning=reasoning,
            tools=tool_defs,
            output_version="responses/v1",
        )

        if not response.output:
            break

        last_msg = response.output[-1]

        # 添加 assistant 消息
        msg = {"role": "assistant", "content": ""}
        if hasattr(last_msg, 'content'):
            msg["content"] = str(last_msg.content)

        # 检查工具调用
        if not hasattr(last_msg, 'tool_calls') or not last_msg.tool_calls:
            messages.append(msg)
            return msg["content"]

        # 有工具调用
        msg["tool_calls"] = [
            {
                "id": tc.id,
                "type": "function",
                "function": {
                    "name": tc.function.name,
                    "arguments": tc.function.arguments
                }
            }
            for tc in last_msg.tool_calls
        ]
        messages.append(msg)

        # 执行工具
        for tc in last_msg.tool_calls:
            tool = tool_map.get(tc.function.name)
            if tool:
                args = json.loads(tc.function.arguments) if isinstance(tc.function.arguments, str) else tc.function.arguments
                result = await tool.ainvoke(args) if hasattr(tool, 'ainvoke') else tool.invoke(args)

                messages.append({
                    "role": "tool",
                    "tool_call_id": tc.id,
                    "content": str(result)
                })

    return messages[-1].get("content", "")

# 使用
for question in questions:
    answer = await simple_reasoning_agent(
        question=question,
        tools=tools,
        model="gpt-4o",
        reasoning={"effort": "high", "summary": "detailed"}
    )
    print(answer)
```

